1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote — base premiums", () => {
6	    it("returns 5G processing fee for an empty item list", () => {
7	      const result = processScenario({
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote" as const, items: [] }],
10	      });
11	      expect(result.results[0]).toEqual({ premium: 5 });
12	    });
13	    it("computes base premium for a single sword (100G + 5G fee)", () => {
14	      const result = processScenario({
15	        customer: { yearsWithMHPCO: 0 },
16	        steps: [
17	          {
18	            op: "quote" as const,
19	            items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
20	          },
21	        ],
22	      });
23	      expect(result.results[0]).toEqual({ premium: 105 });
24	    });
25	    it("computes base premium for a single amulet (60G + 5G fee)", () => {
26	      const result = processScenario({
27	        customer: { yearsWithMHPCO: 0 },
28	        steps: [
29	          {
30	            op: "quote" as const,
31	            items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
32	          },
33	        ],
34	      });
35	      expect(result.results[0]).toEqual({ premium: 65 });
36	    });
37	    it("computes base premium for a single staff (80G + 5G fee)", () => {
38	      const result = processScenario({
39	        customer: { yearsWithMHPCO: 0 },
40	        steps: [
41	          {
42	            op: "quote" as const,
43	            items: [{ type: "staff", material: "oak", enchantment: 0, cursed: false }],
44	          },
45	        ],
46	      });
47	      expect(result.results[0]).toEqual({ premium: 85 });
48	    });
49	    it.todo("computes base premium for a single potion (40G + 5G fee)");
50	    it.todo("computes base premium for a single component (25G + 5G fee)");
51	    it.todo("computes base premium for multiple items (sword + amulet = 160G + 5G fee)");
52	  });
53	
54	  describe("Quote — component block pricing", () => {
55	    it.todo("prices 2 runes at 50G (no block)");
56	    it.todo("prices 3 alike runes at 60G (block of 3)");
57	    it.todo("prices 4 runes at 100G (no block — block requires exactly 3)");
58	    it.todo("prices 3 runes + 3 moonstones at 120G (two separate blocks)");
59	    it.todo("does not apply block for 2 runes + 1 moonstone (different types)");
60	  });
61	
62	  describe("Quote — item-level modifiers", () => {
63	    it.todo("adds 50% cursed surcharge to the cursed item only");
64	    it.todo("adds 30% high-enchantment surcharge for enchantment >= 5");
65	    it.todo("applies both cursed and high-enchantment surcharges to the same item");
66	    it.todo("does not apply high-enchantment surcharge for enchantment 4");
67	    it.todo("item-level modifiers apply only to the affected item in a multi-item policy");
68	  });
69	
70	  describe("Quote — policy-level modifiers", () => {
71	    it.todo("adds 10% first-insurance surcharge on the policy base premium");
72	    it.todo("applies 20% loyalty discount for customer with >= 2 years");
73	    it.todo("applies 15% follow-up discount on second and subsequent quotes");
74	    it.todo("applies all policy-level modifiers together (loyalty + first insurance + follow-up)");
75	  });
76	
77	  describe("Quote — rounding", () => {
78	    it.todo("rounds premium up (ceil) in MHPCO's favor");
79	  });
80	
81	  describe("Quote — integration", () => {
82	    it.todo("newcomer with cursed sword: 165G");
83	    it.todo("long-standing customer second contract with cursed high-enchantment sword: 160G");
84	  });
85	
86	  describe("Quote — errors", () => {
87	    it.todo("throws error for unknown item type");
88	  });
89	
90	  describe("Claim — basic reimbursement", () => {
91	    it.todo("reimburses damage minus 100G deductible for a standard item");
92	    it.todo("reimburses damage to a component minus 100G deductible");
93	    it.todo("applies deductible per damaged item in a multi-item claim");
94	  });
95	
96	  describe("Claim — enchantment and material clauses", () => {
97	    it.todo("reimburses at 50% for items with enchantment >= 8, then deductible");
98	    it.todo("reimburses fully for dragon-material items, then deductible");
99	    it.todo("applies 50% rule when both dragon-material and enchantment >= 8");
100	    it.todo("dragon-material with enchantment < 8 gets full reimbursement minus deductible");
101	  });
102	
103	  describe("Claim — cap", () => {
104	    it.todo("caps total payout at 2x insurance sum");
105	    it.todo("tracks remaining cap across successive claims");
106	    it.todo("cap is based on unmodified insurance values, not premiums");
107	  });
108	
109	  describe("Claim — payout rounding", () => {
110	    it.todo("rounds payout down (floor) in MHPCO's favor");
111	  });
112	
113	  describe("Claim — errors", () => {
114	    it.todo("throws error when damage references an item not in the policy");
115	    it.todo("throws error when more damages of a type than insured items");
116	    it.todo("throws error for negative damage amount");
117	  });
118	});
