1	const PROCESSING_FEE = 5;
2	
3	const basePremium = (item: any): number => {
4	  if (item.type === "sword") return 100;
5	  if (item.type === "amulet") return 60;
6	  if (item.type === "staff") return 80;
7	  return 0;
8	};
9	
10	export function processScenario(scenario: any): { results: { premium: number }[] } {
11	  const results = scenario.steps.map((step: any) => {
12	    const itemTotal = step.items.reduce(
13	      (sum: number, item: any) => sum + basePremium(item),
14	      0,
15	    );
16	    const premium = itemTotal + PROCESSING_FEE;
17	    return { premium };
18	  });
19	  return { results };
20	}
